// ===== CHUYÊN ĐỀ: ĐẠI TỪ (PRONOUNS) — TUẦN 3 =====
const PRNS_THEORY_HTML = "<div class=\"glass rounded-2xl p-4 mb-4\" style=\"border-left:4px solid #2a9d8f\"><div class=\"font-800 text-dark2 mb-2\">🌟 PHẦN 1 — LÝ THUYẾT: ĐẠI TỪ (PRONOUNS)</div><div class=\"text-sm text-soft\">Tài liệu Tuần 3. Tiếng Anh có <b>7 loại đại từ</b>: đại từ nhân xưng, đại từ sở hữu, đại từ phản thân, đại từ bất định, đại từ quan hệ, đại từ chỉ định và đại từ nghi vấn.</div></div><details open class=\"mb-3\"><summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\"><span style=\"background:linear-gradient(90deg,#2a9d8f,#8ecfc7);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">1</span> Đại từ nhân xưng (Personal Pronouns)<i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i></summary><div class=\"mt-2 glass rounded-2xl p-4\" style=\"overflow-x:auto\"><table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\"><thead><tr style=\"background:rgba(42,157,143,.1)\"><th style=\"padding:8px;text-align:left\"></th><th style=\"padding:8px;text-align:left\">Chủ ngữ</th><th style=\"padding:8px;text-align:left\">Tân ngữ</th></tr></thead><tbody><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">Ngôi 1 số ít</td><td style=\"padding:7px 8px\"><b>I</b> (tôi)</td><td style=\"padding:7px 8px\"><b>me</b></td></tr><tr><td style=\"padding:7px 8px\">Ngôi 2 số ít</td><td style=\"padding:7px 8px\"><b>You</b> (bạn)</td><td style=\"padding:7px 8px\"><b>you</b></td></tr><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">Ngôi 3 số ít</td><td style=\"padding:7px 8px\"><b>He/She/It</b></td><td style=\"padding:7px 8px\"><b>him/her/it</b></td></tr><tr><td style=\"padding:7px 8px\">Ngôi 1 số nhiều</td><td style=\"padding:7px 8px\"><b>We</b> (chúng tôi/ta)</td><td style=\"padding:7px 8px\"><b>us</b></td></tr><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">Ngôi 2 số nhiều</td><td style=\"padding:7px 8px\"><b>You</b> (các bạn)</td><td style=\"padding:7px 8px\"><b>you</b></td></tr><tr><td style=\"padding:7px 8px\">Ngôi 3 số nhiều</td><td style=\"padding:7px 8px\"><b>They</b> (họ)</td><td style=\"padding:7px 8px\"><b>them</b></td></tr></tbody></table><div class=\"text-sm text-soft mt-3 mb-1\"><b>Chức năng:</b></div><div class=\"ex-card mt-1\">I/You/He/She/It/We/They + Động từ → làm <b>chủ ngữ</b><br><i>He has lived here for 3 years.</i> <span style=\"color:var(--accent)\">→ Anh ấy đã sống ở đây được 3 năm.</span></div><div class=\"ex-card mt-2\">Động từ/Giới từ + me/you/him/her/it/us/them → làm <b>tân ngữ</b><br><i>She loves him very much.</i> <span style=\"color:var(--accent)\">→ Cô ấy yêu anh ta rất nhiều.</span><br><i>We couldn't do it without her.</i> <span style=\"color:var(--accent)\">→ Chúng tôi không thể làm mà không có cô ấy.</span></div></div></details><details class=\"mb-3\"><summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\"><span style=\"background:linear-gradient(90deg,#2a9d8f,#8ecfc7);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">2</span> Đại từ sở hữu (Possessive Pronouns)<i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i></summary><div class=\"mt-2 glass rounded-2xl p-4\" style=\"overflow-x:auto\"><table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\"><thead><tr style=\"background:rgba(42,157,143,.1)\"><th style=\"padding:8px;text-align:left\">Tính từ sở hữu</th><th style=\"padding:8px;text-align:left\">Đại từ sở hữu</th></tr></thead><tbody><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">my (của tôi)</td><td style=\"padding:7px 8px\">mine</td></tr><tr><td style=\"padding:7px 8px\">your (của bạn)</td><td style=\"padding:7px 8px\">yours</td></tr><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">his (của anh ấy)</td><td style=\"padding:7px 8px\">his</td></tr><tr><td style=\"padding:7px 8px\">her (của cô ấy)</td><td style=\"padding:7px 8px\">hers</td></tr><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">its (của nó)</td><td style=\"padding:7px 8px\">its</td></tr><tr><td style=\"padding:7px 8px\">our (của chúng tôi/ta)</td><td style=\"padding:7px 8px\">ours</td></tr><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">your (của các bạn)</td><td style=\"padding:7px 8px\">yours</td></tr><tr><td style=\"padding:7px 8px\">their (của họ)</td><td style=\"padding:7px 8px\">theirs</td></tr></tbody></table><div class=\"text-sm text-soft mt-3 mb-1\"><b>Chức năng:</b> thay thế cho cụm Tính từ sở hữu + Danh từ (Đại từ sở hữu = Tính từ sở hữu + Danh từ).</div><div class=\"ex-card mt-1\">This is our room. <span style=\"color:var(--accent)\">→ Đây là phòng của chúng ta.</span> (= This is <b>ours</b>.)<br>Where's your pen? <span style=\"color:var(--accent)\">→ Bút của bạn đâu?</span> (= Where's <b>yours</b>?)</div></div></details><details class=\"mb-3\"><summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\"><span style=\"background:linear-gradient(90deg,#2a9d8f,#8ecfc7);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">3</span> Đại từ phản thân (Reflexive Pronouns)<i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i></summary><div class=\"mt-2 glass rounded-2xl p-4\" style=\"overflow-x:auto\"><table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\"><thead><tr style=\"background:rgba(42,157,143,.1)\"><th style=\"padding:8px;text-align:left\">Số ít</th><th style=\"padding:8px;text-align:left\">Số nhiều</th></tr></thead><tbody><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">myself</td><td style=\"padding:7px 8px\">ourselves</td></tr><tr><td style=\"padding:7px 8px\">yourself</td><td style=\"padding:7px 8px\">yourselves</td></tr><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">himself / herself / itself</td><td style=\"padding:7px 8px\">themselves</td></tr></tbody></table><div class=\"text-sm text-soft mt-3 mb-1\"><b>Chức năng:</b></div><div class=\"ex-card mt-1\">Làm tân ngữ khi chủ ngữ và tân ngữ là cùng một người:<br><i>I hurt myself.</i> <span style=\"color:var(--accent)\">→ Tôi tự làm tổn thương chính mình.</span><br><i>He talked to himself.</i> <span style=\"color:var(--accent)\">→ Anh ta tự nói với bản thân.</span></div><div class=\"ex-card mt-2\">Đặt sau danh từ/đại từ để nhấn mạnh:<br><i>The man himself made her a hat.</i> <span style=\"color:var(--accent)\">→ Chính người đàn ông đó đã làm cho cô ấy một cái mũ.</span></div></div></details><details class=\"mb-3\"><summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\"><span style=\"background:linear-gradient(90deg,#2a9d8f,#8ecfc7);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">4</span> Đại từ bất định (Indefinite Pronouns)<i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i></summary><div class=\"mt-2 glass rounded-2xl p-4\" style=\"overflow-x:auto\"><table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\"><thead><tr style=\"background:rgba(42,157,143,.1)\"><th style=\"padding:8px;text-align:left\">Nhóm</th><th style=\"padding:8px;text-align:left\">Cách dùng</th></tr></thead><tbody><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\"><b>some-</b>: something, someone/somebody</td><td style=\"padding:7px 8px\">dùng trong câu khẳng định</td></tr><tr><td style=\"padding:7px 8px\"><b>any-</b>: anything, anyone/anybody</td><td style=\"padding:7px 8px\">dùng trong câu phủ định/nghi vấn</td></tr><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\"><b>every-</b>: everything, everyone/everybody</td><td style=\"padding:7px 8px\">chỉ \"mọi thứ/mọi người\"</td></tr><tr><td style=\"padding:7px 8px\"><b>no-</b>: nothing, no one/nobody</td><td style=\"padding:7px 8px\">chỉ \"không gì/không ai\"</td></tr></tbody></table><div class=\"text-sm text-soft mt-3 mb-1\"><b>Chức năng:</b> làm chủ ngữ (luôn chia động từ số ít) hoặc tân ngữ của động từ/giới từ.</div><div class=\"ex-card mt-1\"><i>Nobody is in the room.</i> <span style=\"color:var(--accent)\">→ Không có ai ở trong phòng cả.</span><br><i>She didn't invite anyone to the party.</i> <span style=\"color:var(--accent)\">→ Cô ấy không mời ai tới bữa tiệc cả.</span></div></div></details><details class=\"mb-3\"><summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\"><span style=\"background:linear-gradient(90deg,#2a9d8f,#8ecfc7);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">5</span> Đại từ quan hệ (Relative Pronouns)<i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i></summary><div class=\"mt-2 glass rounded-2xl p-4\" style=\"overflow-x:auto\"><table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\"><thead><tr style=\"background:rgba(42,157,143,.1)\"><th style=\"padding:8px;text-align:left\"></th><th style=\"padding:8px;text-align:left\">Dùng cho người</th><th style=\"padding:8px;text-align:left\">Dùng cho vật</th></tr></thead><tbody><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">Chủ ngữ</td><td style=\"padding:7px 8px\">Who / that</td><td style=\"padding:7px 8px\">Which / that</td></tr><tr><td style=\"padding:7px 8px\">Tân ngữ</td><td style=\"padding:7px 8px\">Whom / that</td><td style=\"padding:7px 8px\">Which / that</td></tr><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">Sở hữu</td><td colspan=\"2\" style=\"padding:7px 8px\">Whose</td></tr></tbody></table><div class=\"text-sm text-soft mt-3 mb-1\"><b>Chức năng:</b></div><div class=\"ex-card mt-1\">Làm chủ ngữ: <i>This is the house that/which was built in 2000.</i> <span style=\"color:var(--accent)\">→ Đây là ngôi nhà được xây năm 2000.</span></div><div class=\"ex-card mt-2\">Làm tân ngữ: <i>The woman whom I saw yesterday is Mary's aunt.</i> <span style=\"color:var(--accent)\">→ Người phụ nữ tôi gặp hôm qua là dì của Mary.</span></div><div class=\"ex-card mt-2\">Sở hữu (whose + danh từ): <i>The film is about a boy whose mom is a famous singer.</i> <span style=\"color:var(--accent)\">→ Bộ phim kể về một cậu bé có mẹ là ca sĩ nổi tiếng.</span></div><div class=\"mt-2 p-2 rounded-xl\" style=\"background:#fff3cd;font-size:12px\">💡 Lưu ý: không dùng \"that\" trong mệnh đề quan hệ không xác định (có dấu phẩy).</div></div></details><details class=\"mb-3\"><summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\"><span style=\"background:linear-gradient(90deg,#2a9d8f,#8ecfc7);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">6</span> Đại từ chỉ định (Demonstrative Pronouns)<i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i></summary><div class=\"mt-2 glass rounded-2xl p-4\" style=\"overflow-x:auto\"><table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\"><thead><tr style=\"background:rgba(42,157,143,.1)\"><th style=\"padding:8px;text-align:left\">Số ít</th><th style=\"padding:8px;text-align:left\">Số nhiều</th></tr></thead><tbody><tr style=\"background:rgba(42,157,143,.04)\"><td style=\"padding:7px 8px\">This (Này) — gần</td><td style=\"padding:7px 8px\">These — gần</td></tr><tr><td style=\"padding:7px 8px\">That (Kia) — xa</td><td style=\"padding:7px 8px\">Those — xa</td></tr></tbody></table><div class=\"ex-card mt-2\"><i>This is a good student.</i> <span style=\"color:var(--accent)\">→ Đây là một học sinh giỏi.</span> (gần)<br><i>That is an old table.</i> <span style=\"color:var(--accent)\">→ Cái bàn kia cũ rồi.</span> (xa)<br><i>These are nice flowers.</i> / <i>Those are Mike's cars.</i></div></div></details><details class=\"mb-3\"><summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\"><span style=\"background:linear-gradient(90deg,#2a9d8f,#8ecfc7);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">7</span> Đại từ nghi vấn (Interrogative Pronouns)<i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i></summary><div class=\"mt-2 glass rounded-2xl p-4\"><div class=\"text-sm text-soft mb-2\">who (ai), whom (ai), whose (của ai/cái gì), what (cái gì), which (người nào/cái nào)</div><div class=\"ex-card mt-1\">Làm chủ ngữ: <i>Who knows the answer?</i> <span style=\"color:var(--accent)\">→ Ai biết câu trả lời?</span></div><div class=\"ex-card mt-2\">Làm tân ngữ: <i>Who does he usually meet?</i> <span style=\"color:var(--accent)\">→ Anh ta thường gặp ai?</span><br><i>Whose book did you borrow?</i> <span style=\"color:var(--accent)\">→ Bạn đã mượn cuốn sách của ai?</span></div></div></details><div class=\"mt-3 p-3 rounded-xl\" style=\"background:#fff3cd;border-left:3px solid #ffc107;font-size:13px\">💡 <b>Mẹo:</b> Sau khi nắm lý thuyết, hãy làm <b>Phần 2 — Bài tập</b> để luyện các dạng: điền đại từ, tìm lỗi sai, trắc nghiệm và viết lại câu.</div>";

const PRNS_EX1_Q = [
{id:"pron_ex1_1",type:"typing",q:"My name is Lan. …….…….. am Vietnamese.",vi:"",answer:"I",accept:["i"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: I</div><div class=\"ex-card mb-2\">My name is Lan. …….…….. am Vietnamese.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Chủ ngữ của câu cần đại từ nhân xưng chủ ngữ ngôi thứ nhất số ít 'I' (thay cho 'Lan').</div>"},
{id:"pron_ex1_2",type:"typing",q:"My parents live in Ho Chi Minh City. We visit ……………………. often.",vi:"",answer:"them",accept:["them"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: them</div><div class=\"ex-card mb-2\">My parents live in Ho Chi Minh City. We visit ……………………. often.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Tân ngữ của động từ 'visit', thay cho 'my parents' (số nhiều, ngôi 3) → 'them'.</div>"},
{id:"pron_ex1_3",type:"typing",q:"It's a good story. Do you want to read………………..?",vi:"",answer:"it",accept:["it"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: it</div><div class=\"ex-card mb-2\">It's a good story. Do you want to read………………..?</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Tân ngữ của động từ 'read', thay cho 'a good story' (vật, số ít) → 'it'.</div>"},
{id:"pron_ex1_4",type:"typing",q:"Can you show ………………. where I can find a good hotel in this city?",vi:"",answer:"me",accept:["me"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: me</div><div class=\"ex-card mb-2\">Can you show ………………. where I can find a good hotel in this city?</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Tân ngữ của động từ 'show', chỉ người nói (ngôi thứ nhất số ít) → 'me'.</div>"},
{id:"pron_ex1_5",type:"typing",q:"I know Linh well but …………………. doesn't know me.",vi:"",answer:"she",accept:["she"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: she</div><div class=\"ex-card mb-2\">I know Linh well but …………………. doesn't know me.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Chủ ngữ của động từ 'doesn't know', thay cho 'Linh' (nữ, số ít) → 'she'.</div>"},
{id:"pron_ex1_6",type:"typing",q:"Mrs Hoa has got a son. She loves ………………..a lot.",vi:"",answer:"him",accept:["him"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: him</div><div class=\"ex-card mb-2\">Mrs Hoa has got a son. She loves ………………..a lot.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Tân ngữ của động từ 'loves', thay cho 'a son' (nam, số ít) → 'him'.</div>"},
{id:"pron_ex1_7",type:"typing",q:"My children study at Chu Van An High School. ………………….go to school on weekdays.",vi:"",answer:"They",accept:["they"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: They</div><div class=\"ex-card mb-2\">My children study at Chu Van An High School. ………………….go to school on weekdays.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Chủ ngữ của động từ 'go', thay cho 'My children' (số nhiều) → 'They'.</div>"},
{id:"pron_ex1_8",type:"typing",q:"We showed them some of ……………… photos.",vi:"",answer:"our",accept:["our"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: our</div><div class=\"ex-card mb-2\">We showed them some of ……………… photos.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Tính từ sở hữu đứng trước danh từ 'photos', chỉ sở hữu của 'We' → 'our'.</div>"},
{id:"pron_ex1_9",type:"typing",q:"They say that our school uniform is much nicer than …………………….",vi:"",answer:"theirs",accept:["theirs"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: theirs</div><div class=\"ex-card mb-2\">They say that our school uniform is much nicer than …………………….</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Đại từ sở hữu thay cho 'their school uniform', đứng độc lập sau 'than' → 'theirs'.</div>"},
{id:"pron_ex1_10",type:"typing",q:"The children made the entire meal by……………….",vi:"",answer:"themselves",accept:["themselves"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: themselves</div><div class=\"ex-card mb-2\">The children made the entire meal by……………….</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Đại từ phản thân trong cụm 'by themselves' (tự làm lấy), thay cho 'the children' (số nhiều) → 'themselves'.</div>"},
];

const PRNS_EX2_Q = [
{id:"pron_ex2_11",type:"typing",q:"I am so sad. I need………………………… to talk with.",vi:"",answer:"someone",accept:["someone", "somebody"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: someone</div><div class=\"ex-card mb-2\">I am so sad. I need………………………… to talk with.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Câu khẳng định, cần đại từ bất định nhóm 'some-' chỉ người → 'someone/somebody'.</div>"},
{id:"pron_ex2_12",type:"typing",q:"The room was empty. There was ………………………….there.",vi:"",answer:"nobody",accept:["nobody", "no one"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: nobody</div><div class=\"ex-card mb-2\">The room was empty. There was ………………………….there.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Phòng trống (không có ai) → đại từ bất định nhóm 'no-' chỉ người → 'nobody/no one'.</div>"},
{id:"pron_ex2_13",type:"typing",q:"……………………is here. Let's start the meeting.",vi:"",answer:"Everyone",accept:["everyone", "everybody"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: Everyone</div><div class=\"ex-card mb-2\">……………………is here. Let's start the meeting.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Ý nói 'mọi người đã có mặt' → đại từ bất định nhóm 'every-' chỉ người → 'Everyone/Everybody'.</div>"},
{id:"pron_ex2_14",type:"typing",q:"…………………… is impossible.",vi:"",answer:"Nothing",accept:["nothing"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: Nothing</div><div class=\"ex-card mb-2\">…………………… is impossible.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Ý nói 'không có việc gì là không thể' → đại từ bất định nhóm 'no-' chỉ vật → 'Nothing'.</div>"},
{id:"pron_ex2_15",type:"typing",q:"I'm looking for my motorbike. Has …………………………..seen it?",vi:"",answer:"anyone",accept:["anyone", "anybody"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: anyone</div><div class=\"ex-card mb-2\">I'm looking for my motorbike. Has …………………………..seen it?</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Câu nghi vấn, cần đại từ bất định nhóm 'any-' chỉ người → 'anyone/anybody'.</div>"},
{id:"pron_ex2_16",type:"typing",q:"Don't worry! ……………………will be OK.",vi:"",answer:"Everything",accept:["everything"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: Everything</div><div class=\"ex-card mb-2\">Don't worry! ……………………will be OK.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Ý nói 'mọi việc sẽ ổn' → đại từ bất định nhóm 'every-' chỉ vật → 'Everything'.</div>"},
{id:"pron_ex2_17",type:"typing",q:"I'm hungry. Have you got………………………..to eat?",vi:"",answer:"anything",accept:["anything"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: anything</div><div class=\"ex-card mb-2\">I'm hungry. Have you got………………………..to eat?</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Câu nghi vấn, cần đại từ bất định nhóm 'any-' chỉ vật → 'anything'.</div>"},
{id:"pron_ex2_18",type:"typing",q:"There is………………………wrong here. I can't start my car.",vi:"",answer:"something",accept:["something"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: something</div><div class=\"ex-card mb-2\">There is………………………wrong here. I can't start my car.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Câu khẳng định (khẳng định có vấn đề) → đại từ bất định nhóm 'some-' chỉ vật → 'something'.</div>"},
{id:"pron_ex2_19",type:"typing",q:"If you remember ………………………….. at all, please let us know.",vi:"",answer:"anything",accept:["anything"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: anything</div><div class=\"ex-card mb-2\">If you remember ………………………….. at all, please let us know.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Trong mệnh đề điều kiện 'if' (mang tính giả định/phủ định), dùng nhóm 'any-' → 'anything'.</div>"},
{id:"pron_ex2_20",type:"typing",q:"Would you like ……….. to drink?",vi:"",answer:"something",accept:["something"],explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: something</div><div class=\"ex-card mb-2\">Would you like ……….. to drink?</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">Lời mời/đề nghị (thường mang nghĩa khẳng định dù ở dạng câu hỏi) → dùng nhóm 'some-' → 'something'.</div>"},
];

const PRNS_EX3_Q = [
{id:"pron_ex3_21",type:"fill",q:"This is the girl ___ works at a hospital.",vi:"",opts:["A. who", "B. whom", "C. which"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. who</div><div class=\"ex-card mb-2\">This is the girl ___ works at a hospital.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'who' đúng vì làm chủ ngữ, thay cho người 'the girl'; 'whom' dùng cho tân ngữ; 'which' dùng cho vật.</div>"},
{id:"pron_ex3_22",type:"fill",q:"The woman ___ I met yesterday is a famous doctor.",vi:"",opts:["A. which", "B. whom", "C. whose"],ans:1,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. whom</div><div class=\"ex-card mb-2\">The woman ___ I met yesterday is a famous doctor.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'whom' đúng vì làm tân ngữ của động từ 'met', thay cho người; 'which' dùng cho vật; 'whose' chỉ sở hữu.</div>"},
{id:"pron_ex3_23",type:"fill",q:"The film ___ won the OSCAR is about a terrible pandemic.",vi:"",opts:["A. who", "B. which", "C. whose"],ans:1,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. which</div><div class=\"ex-card mb-2\">The film ___ won the OSCAR is about a terrible pandemic.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'which' đúng vì làm chủ ngữ, thay cho vật 'the film'; 'who' dùng cho người; 'whose' chỉ sở hữu.</div>"},
{id:"pron_ex3_24",type:"fill",q:"I have a brother ___ always makes my parents sad.",vi:"",opts:["A. who", "B. whom", "C. which"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. who</div><div class=\"ex-card mb-2\">I have a brother ___ always makes my parents sad.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'who' đúng vì làm chủ ngữ, thay cho người 'a brother'; 'whom' dùng cho tân ngữ; 'which' dùng cho vật.</div>"},
{id:"pron_ex3_25",type:"fill",q:"My hometown, ___ is famous for green tea, is located in the north of Vietnam.",vi:"",opts:["A. which", "B. who", "C. that"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. which</div><div class=\"ex-card mb-2\">My hometown, ___ is famous for green tea, is located in the north of Vietnam.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'which' đúng vì đây là mệnh đề quan hệ không xác định (có dấu phẩy) chỉ vật/nơi chốn; không dùng 'that' trong mệnh đề có dấu phẩy; 'who' dùng cho người.</div>"},
{id:"pron_ex3_26",type:"fill",q:"The boy ___ father is a footballer can play football well.",vi:"",opts:["A. whose", "B. whom", "C. who"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. whose</div><div class=\"ex-card mb-2\">The boy ___ father is a footballer can play football well.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'whose' đúng vì chỉ sở hữu (cha của cậu bé); 'whom'/'who' không chỉ sở hữu.</div>"},
{id:"pron_ex3_27",type:"fill",q:"The laptop ___ I bought last year still works well.",vi:"",opts:["A. who", "B. whom", "C. which"],ans:2,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. which</div><div class=\"ex-card mb-2\">The laptop ___ I bought last year still works well.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'which' đúng vì làm tân ngữ, thay cho vật 'the laptop'; 'who'/'whom' dùng cho người.</div>"},
{id:"pron_ex3_28",type:"fill",q:"There are many people ___ can eat nothing for many days.",vi:"",opts:["A. who", "B. whom", "C. whose"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. who</div><div class=\"ex-card mb-2\">There are many people ___ can eat nothing for many days.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'who' đúng vì làm chủ ngữ, thay cho người 'many people'; 'whom' dùng cho tân ngữ; 'whose' chỉ sở hữu.</div>"},
{id:"pron_ex3_29",type:"fill",q:"A bus is a big car ___ carries a lot of people.",vi:"",opts:["A. whose", "B. whom", "C. that"],ans:2,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. that</div><div class=\"ex-card mb-2\">A bus is a big car ___ carries a lot of people.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'that' đúng vì làm chủ ngữ thay cho vật 'a big car' trong mệnh đề quan hệ xác định; 'whose' chỉ sở hữu; 'whom' dùng cho người.</div>"},
{id:"pron_ex3_30",type:"fill",q:"The singer ___ many young people like can dance as well.",vi:"",opts:["A. which", "B. whom", "C. whose"],ans:1,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. whom</div><div class=\"ex-card mb-2\">The singer ___ many young people like can dance as well.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'whom' đúng vì làm tân ngữ của động từ 'like', thay cho người 'the singer'; 'which' dùng cho vật; 'whose' chỉ sở hữu.</div>"},
{id:"pron_ex3_31",type:"fill",q:"Linda, ___ is my mother, Anne.",vi:"",opts:["A. this", "B. that", "C. these"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. this</div><div class=\"ex-card mb-2\">Linda, ___ is my mother, Anne.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'this' đúng vì dùng để giới thiệu một người/vật ở gần (số ít); 'that' chỉ vị trí xa; 'these' là số nhiều.</div>"},
{id:"pron_ex3_32",type:"fill",q:"Is ___ your brother over there?",vi:"",opts:["A. this", "B. that", "C. those"],ans:1,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. that</div><div class=\"ex-card mb-2\">Is ___ your brother over there?</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'that' đúng vì 'over there' chỉ vị trí xa người nói, số ít; 'this' chỉ vị trí gần; 'those' là số nhiều.</div>"},
{id:"pron_ex3_33",type:"fill",q:"I'll post ___ letters on my way home.",vi:"",opts:["A. this", "B. that", "C. these"],ans:2,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. these</div><div class=\"ex-card mb-2\">I'll post ___ letters on my way home.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'these' đúng vì 'letters' là danh từ số nhiều, chỉ vị trí gần (đang cầm trên tay); 'this'/'that' là số ít.</div>"},
{id:"pron_ex3_34",type:"fill",q:"___ makes the decisions here?",vi:"",opts:["A. Who", "B. Whom", "C. What"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. Who</div><div class=\"ex-card mb-2\">___ makes the decisions here?</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'Who' đúng vì làm chủ ngữ của câu hỏi, hỏi về người thực hiện hành động; 'Whom' dùng cho tân ngữ; 'What' hỏi về vật/sự việc.</div>"},
{id:"pron_ex3_35",type:"fill",q:"___ did you talk to?",vi:"",opts:["A. Who", "B. Whose", "C. What"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. Who</div><div class=\"ex-card mb-2\">___ did you talk to?</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'Who' đúng (trong văn nói hiện đại, dùng 'Who' thay cho 'Whom' làm tân ngữ của giới từ 'to' ở cuối câu); 'Whose' hỏi sở hữu; 'What' hỏi về vật.</div>"},
];

const PRNS_D15_Q = [
{id:"pron_d15_1",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>You usually have to wait for a long time. Nothing happen quickly.</i>",vi:"",opts:["A. have to", "B. for", "C. long", "D. happen"],ans:3,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: D. happen → sửa thành: <b>happens</b></div><div class=\"ex-card mb-2\">You usually have to wait for a long time. Nothing happen quickly.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'Nothing' là đại từ bất định, luôn chia động từ số ít, nên 'happen' phải sửa thành 'happens'.</div>"},
{id:"pron_d15_2",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>My close friends have spent most of her free time helping homeless people.</i>",vi:"",opts:["A. close", "B. have spent", "C. her", "D. helping"],ans:2,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: C. her → sửa thành: <b>their</b></div><div class=\"ex-card mb-2\">My close friends have spent most of her free time helping homeless people.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'her' phải sửa thành 'their' vì thay thế cho 'my close friends' (số nhiều).</div>"},
{id:"pron_d15_3",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>It can be an amazing experience for the people who have the courage to leave his family and friends and settle down in a new place.</i>",vi:"",opts:["A. amazing", "B. who", "C. his", "D. down"],ans:2,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: C. his → sửa thành: <b>their</b></div><div class=\"ex-card mb-2\">It can be an amazing experience for the people who have the courage to leave his family and friends and settle down in a new place.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'his' phải sửa thành 'their' vì thay thế cho 'the people' (số nhiều).</div>"},
{id:"pron_d15_4",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>\"Whom advice did you follow?\", he asked his friend.</i>",vi:"",opts:["A. Whom", "B. did", "C. follow", "D. his"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: A. Whom → sửa thành: <b>Whose</b></div><div class=\"ex-card mb-2\">\"Whom advice did you follow?\", he asked his friend.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'Whom' phải sửa thành 'Whose' vì cần đại từ nghi vấn chỉ sở hữu đứng trước danh từ 'advice'.</div>"},
{id:"pron_d15_5",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>Who are the things that bring you joy and satisfaction in your daily life?</i>",vi:"",opts:["A. Who", "B. that", "C. satisfaction", "D. your"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: A. Who → sửa thành: <b>What</b></div><div class=\"ex-card mb-2\">Who are the things that bring you joy and satisfaction in your daily life?</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'Who' phải sửa thành 'What' vì hỏi về vật/sự việc ('the things'), không phải người.</div>"},
{id:"pron_d15_6",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>If he gets those job in London, he'll be able to visit us more often.</i>",vi:"",opts:["A. those", "B. in", "C. be able", "D. us"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: A. those → sửa thành: <b>that/a</b></div><div class=\"ex-card mb-2\">If he gets those job in London, he'll be able to visit us more often.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'those' phải sửa thành 'that' hoặc 'a' vì 'job' là danh từ số ít.</div>"},
{id:"pron_d15_7",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>The students whom study hard usually get good grades.</i>",vi:"",opts:["A. The", "B. whom", "C. get", "D. grades"],ans:1,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B. whom → sửa thành: <b>who</b></div><div class=\"ex-card mb-2\">The students whom study hard usually get good grades.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'whom' phải sửa thành 'who' vì làm chủ ngữ của động từ 'study', không phải tân ngữ.</div>"},
{id:"pron_d15_8",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>That movie, that we watched last night, was really interesting.</i>",vi:"",opts:["A. That", "B. that", "C. watched", "D. interesting"],ans:1,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B. that → sửa thành: <b>which</b></div><div class=\"ex-card mb-2\">That movie, that we watched last night, was really interesting.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'that' (thứ hai) phải sửa thành 'which' vì đây là mệnh đề quan hệ không xác định (có dấu phẩy), không được dùng 'that'.</div>"},
{id:"pron_d15_9",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>The puzzle was so difficult that nobody was able to solve them in the allotted time.</i>",vi:"",opts:["A. The", "B. difficult", "C. nobody", "D. them"],ans:3,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: D. them → sửa thành: <b>it</b></div><div class=\"ex-card mb-2\">The puzzle was so difficult that nobody was able to solve them in the allotted time.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'them' phải sửa thành 'it' vì thay thế cho 'the puzzle' (số ít).</div>"},
{id:"pron_d15_10",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>They sold everyone they owned before moving to a new country.</i>",vi:"",opts:["A. everyone", "B. owned", "C. moving", "D. country"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: A. everyone → sửa thành: <b>everything</b></div><div class=\"ex-card mb-2\">They sold everyone they owned before moving to a new country.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'everyone' phải sửa thành 'everything' vì nói về đồ vật họ sở hữu (bán đồ đạc), không phải người.</div>"},
{id:"pron_d15_11",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>Despite the challenges, she managed to complete the project entirely by himself.</i>",vi:"",opts:["A. Despite", "B. to complete", "C. entirely", "D. himself"],ans:3,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: D. himself → sửa thành: <b>herself</b></div><div class=\"ex-card mb-2\">Despite the challenges, she managed to complete the project entirely by himself.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'himself' phải sửa thành 'herself' vì thay thế cho 'she' (nữ).</div>"},
{id:"pron_d15_12",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>Nicky and I both have red hair but her is lighter than mine.</i>",vi:"",opts:["A. and", "B. both", "C. her", "D. mine"],ans:2,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: C. her → sửa thành: <b>hers</b></div><div class=\"ex-card mb-2\">Nicky and I both have red hair but her is lighter than mine.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'her' phải sửa thành 'hers' (đại từ sở hữu đứng độc lập làm chủ ngữ), không dùng tính từ sở hữu 'her'.</div>"},
{id:"pron_d15_13",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>The emotions in the poems are these of loss and grief.</i>",vi:"",opts:["A. emotions", "B. poems", "C. these", "D. grief"],ans:2,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: C. these → sửa thành: <b>those</b></div><div class=\"ex-card mb-2\">The emotions in the poems are these of loss and grief.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'these' phải sửa thành 'those' (those of = những cái/điều của...), vì 'the emotions' số nhiều và ở xa về mặt cấu trúc câu.</div>"},
{id:"pron_d15_14",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>Can someone play the piano? We need a musician for the event.</i>",vi:"",opts:["A. someone", "B. the", "C. a", "D. the"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: A. someone → sửa thành: <b>anyone</b></div><div class=\"ex-card mb-2\">Can someone play the piano? We need a musician for the event.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'someone' nên sửa thành 'anyone' vì đây là câu hỏi trung lập hỏi về khả năng chung, phù hợp hơn với 'any-'.</div>"},
{id:"pron_d15_15",type:"fill",q:"Tìm phần có lỗi sai (gạch chân A, B, C, D):<br><i>At the moment, the multinational corporation is in the process of upgrading their departments.</i>",vi:"",opts:["A. At", "B. is", "C. process", "D. their"],ans:3,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: D. their → sửa thành: <b>its</b></div><div class=\"ex-card mb-2\">At the moment, the multinational corporation is in the process of upgrading their departments.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'their' phải sửa thành 'its' vì thay thế cho 'the multinational corporation' (số ít, một công ty).</div>"},
];

const PRNS_D16_Q = [
{id:"pron_d16_1",type:"fill",q:"____________ enjoy spending our weekends hiking in the mountains.",vi:"",opts:["A. We", "B. You", "C. Me", "D. They"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. We</div><div class=\"ex-card mb-2\">____________ enjoy spending our weekends hiking in the mountains.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'We' đúng vì phải khớp với tính từ sở hữu 'our' phía sau (chúng ta thích dành cuối tuần...); 'You'/'They' không khớp với 'our'; 'Me' không thể làm chủ ngữ.</div>"},
{id:"pron_d16_2",type:"fill",q:"I often see __________ jogging in the park early in the morning.",vi:"",opts:["A. he", "B. him", "C. his", "D. All are correct"],ans:1,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. him</div><div class=\"ex-card mb-2\">I often see __________ jogging in the park early in the morning.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'him' đúng vì làm tân ngữ của động từ 'see'; 'he' là chủ ngữ (sai vị trí); 'his' là sở hữu (sai).</div>"},
{id:"pron_d16_3",type:"fill",q:"Our company is expanding ____________ operations internationally.",vi:"",opts:["A. it", "B. its", "C. they", "D. their"],ans:1,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. its</div><div class=\"ex-card mb-2\">Our company is expanding ____________ operations internationally.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'its' đúng vì là tính từ sở hữu số ít, khớp với 'our company' (một công ty); 'their' dùng cho số nhiều.</div>"},
{id:"pron_d16_4",type:"fill",q:"It's important to make sure _____________understands the instructions.",vi:"",opts:["A. everybody", "B. no one", "C. anyone", "D. someone"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. everybody</div><div class=\"ex-card mb-2\">It's important to make sure _____________understands the instructions.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'everybody' đúng vì ngữ cảnh khẳng định muốn đảm bảo TẤT CẢ mọi người hiểu; 'no one' mang nghĩa phủ định không hợp; 'anyone'/'someone' không nhấn mạnh được toàn bộ mọi người bằng 'everybody'.</div>"},
{id:"pron_d16_5",type:"fill",q:"Everything ___________ possible if you set your mind to it.",vi:"",opts:["A. is", "B. are", "C. was", "D. were"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. is</div><div class=\"ex-card mb-2\">Everything ___________ possible if you set your mind to it.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'is' đúng vì 'Everything' là đại từ bất định, luôn chia động từ số ít ở thì hiện tại.</div>"},
{id:"pron_d16_6",type:"fill",q:"If _____________has objections, speak now or forever hold your peace.",vi:"",opts:["A. someone", "B. something", "C. anyone", "D. no one"],ans:2,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. anyone</div><div class=\"ex-card mb-2\">If _____________has objections, speak now or forever hold your peace.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'anyone' đúng vì đây là mệnh đề điều kiện (if), thường dùng nhóm 'any-'; 'someone' dùng trong câu khẳng định; 'no one' mang nghĩa phủ định không hợp mệnh đề điều kiện mở.</div>"},
{id:"pron_d16_7",type:"fill",q:"No one has been to that restaurant, have __________?",vi:"",opts:["A. he", "B. she", "C. we", "D. they"],ans:3,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. they</div><div class=\"ex-card mb-2\">No one has been to that restaurant, have __________?</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'they' đúng vì trong câu hỏi đuôi (tag question), 'no one' được thay bằng 'they' ở mệnh đề hỏi đuôi theo quy ước ngữ pháp tiếng Anh hiện đại.</div>"},
{id:"pron_d16_8",type:"fill",q:"The company ____________products are highly recommended has just launched a new line.",vi:"",opts:["A. which", "B. that", "C. whose", "D. whom"],ans:2,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. whose</div><div class=\"ex-card mb-2\">The company ____________products are highly recommended has just launched a new line.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'whose' đúng vì cần đại từ quan hệ chỉ sở hữu đứng trước danh từ 'products' (sản phẩm CỦA công ty).</div>"},
{id:"pron_d16_9",type:"fill",q:"The project _____________took months to complete was a great success.",vi:"",opts:["A. that", "B. who", "C. whom", "D. whose"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. that</div><div class=\"ex-card mb-2\">The project _____________took months to complete was a great success.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'that' đúng vì làm chủ ngữ, thay cho vật 'the project'; 'who'/'whom' dùng cho người; 'whose' chỉ sở hữu.</div>"},
{id:"pron_d16_10",type:"fill",q:"Do you know anyone ________ can fix a leaking faucet?",vi:"",opts:["A. whom", "B. which", "C. whose", "D. that"],ans:3,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. that</div><div class=\"ex-card mb-2\">Do you know anyone ________ can fix a leaking faucet?</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'that' đúng vì làm chủ ngữ thay cho người 'anyone' (trong 4 đáp án, 'that' là lựa chọn hợp lệ duy nhất cho chủ ngữ chỉ người ở đây); 'whom' dùng cho tân ngữ; 'which' dùng cho vật; 'whose' chỉ sở hữu.</div>"},
{id:"pron_d16_11",type:"fill",q:"Tom told __________not to worry about the upcoming exam; he had studied hard.",vi:"",opts:["A. herself", "B. himself", "C. themselves", "D. myself"],ans:1,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. himself</div><div class=\"ex-card mb-2\">Tom told __________not to worry about the upcoming exam; he had studied hard.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'himself' đúng vì đại từ phản thân phải khớp với chủ ngữ 'Tom' (nam, số ít).</div>"},
{id:"pron_d16_12",type:"fill",q:"Sarah decorated ________ entire house by herself for the upcoming party.",vi:"",opts:["A. his", "B. him", "C. hers", "D. the"],ans:3,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. the</div><div class=\"ex-card mb-2\">Sarah decorated ________ entire house by herself for the upcoming party.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'the' đúng vì dùng mạo từ xác định trước danh từ 'entire house' (Sarah tự trang trí NGÔI NHÀ, không cần lặp lại sở hữu vì đã có 'by herself'); 'his'/'him'/'hers' đều không hợp ngữ pháp/nghĩa ở vị trí này.</div>"},
{id:"pron_d16_13",type:"fill",q:"He inherited a house___________ history dates back to the 18th century.",vi:"",opts:["A. whose", "B. which", "C. that", "D. All are correct"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. whose</div><div class=\"ex-card mb-2\">He inherited a house___________ history dates back to the 18th century.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'whose' đúng vì cần đại từ quan hệ chỉ sở hữu (lịch sử CỦA ngôi nhà) đứng trước danh từ 'history'; 'which'/'that' không chỉ sở hữu.</div>"},
{id:"pron_d16_14",type:"fill",q:"I'm meeting up with a friend of __________for coffee this afternoon.",vi:"",opts:["A. me", "B. mine", "C. my", "D. I"],ans:1,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. mine</div><div class=\"ex-card mb-2\">I'm meeting up with a friend of __________for coffee this afternoon.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'mine' đúng vì đây là cấu trúc sở hữu kép 'a friend of mine' (một người bạn CỦA TÔI); 'me'/'my'/'I' đều sai hình thức ở vị trí này.</div>"},
{id:"pron_d16_15",type:"fill",q:"His dedication to his work was exemplary, exceeding ___________ the other employees.",vi:"",opts:["A. that of", "B. that", "C. those of", "D. those"],ans:0,explain_detail:"<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. that of</div><div class=\"ex-card mb-2\">His dedication to his work was exemplary, exceeding ___________ the other employees.</div><div class=\"ex-card mb-2\" style=\"font-size:13px\">'that of' đúng vì thay thế cho 'the dedication of' (sự tận tâm CỦA những nhân viên khác) — 'dedication' là danh từ không đếm được/số ít nên dùng 'that of'; 'those of' dùng cho danh từ số nhiều.</div>"},
];

